@media print {
  /* ナビゲーション・フッターを非表示 */
  nav, footer, .sidebar, .no-print {
    display: none !important;
  }

  /* 背景色を強制印刷 */
  body {
    -webkit-print-color-adjust: exact;
    print-color-adjust: exact;
  }

  /* リンクURLを表示 */
  a[href]::after {
    content: ' (' attr(href) ')';
    font-size: 0.8em;
    color: #666;
  }

  /* フォントサイズ調整 */
  body { font-size: 12pt; }
  h1 { font-size: 18pt; }
}

/* ページ全体の設定 */
@page {
  size: A4 portrait;
  margin: 2cm;
}

/* 最初のページだけ余白を広く */
@page :first {
  margin-top: 4cm;
}

/* 左右ページで余白を変える（両面印刷） */
@page :left {
  margin-left: 3cm;
  margin-right: 2cm;
}
@page :right {
  margin-left: 2cm;
  margin-right: 3cm;
}

/* 見出しの前で改ページ */
h2 {
  break-before: page;
}

/* 要素の途中で分割しない */
.card, .table-row, figure {
  break-inside: avoid;
}

/* 要素の後で改ページ */
.chapter-end {
  break-after: page;
}

/* 段組みでの分割制御 */
.column-item {
  break-inside: avoid-column;
}

/* 段落の孤立行を防ぐ */
p {
  widows: 3;  /* ページ先頭に最低3行 */
  orphans: 3; /* ページ末尾に最低3行 */
}

@media print {
  /* 1. 不要要素を非表示 */
  nav, .sidebar, .ads, .no-print,
  button, .fab, .modal { display: none !important; }

  /* 2. 色とフォント */
  body {
    color: #000;
    background: #fff;
    font-size: 12pt;
    line-height: 1.5;
  }

  /* 3. リンクURLを表示 */
  a[href^="http"]::after {
    content: ' (' attr(href) ')';
    font-size: 0.8em;
    color: #555;
    word-break: break-all;
  }
  a[href^="#"]::after { content: none; }

  /* 4. 改ページ制御 */
  h2, h3 { break-after: avoid; }
  img, figure, table { break-inside: avoid; }

  /* 5. テーブルヘッダー繰り返し */
  thead { display: table-header-group; }
  tfoot { display: table-footer-group; }

  /* 6. 孤立行防止 */
  p { widows: 3; orphans: 3; }
}

/* 背景色を印刷に含める */
.colored-section {
  background: #3b82f6;
  color: #fff;
  -webkit-print-color-adjust: exact;
  print-color-adjust: exact;
}

/* テーブルの縞模様を印刷に含める */
table {
  -webkit-print-color-adjust: exact;
  print-color-adjust: exact;
}

/* 高コントラスト要求時 */
@media (prefers-contrast: more) {
  :root {
    --border: #000;
    --text: #000;
    --bg: #fff;
  }
  button {
    border: 2px solid #000;
  }
}

/* 低コントラスト要求時 */
@media (prefers-contrast: less) {
  :root {
    --text: #555;
    --border: #ddd;
  }
}

/* 強制カラーモード（Windows ハイコントラスト） */
@media (forced-colors: active) {
  .custom-btn {
    border: 1px solid ButtonText;
  }
}

/* 列数を指定 */
.article {
  column-count: 3;
  column-gap: 24px;
  column-rule: 1px solid #e5e7eb;
}

/* 列幅で自動列数 */
.content {
  column-width: 250px;
  column-gap: 20px;
}

/* 列をまたぐ要素 */
h2 {
  column-span: all;
}

/* 列内で分割しない */
.card {
  break-inside: avoid;
}
